export function getPluginEnabledStateKey(pluginId: string) {
  return `plugins.enabled.${pluginId}`;
}

export function getPluginsDevelopmentModeStateKey() {
  return "plugins.developmentMode";
}

export function getPluginsAutoUpdateStateKey() {
  return "plugins.updates.autoInstall";
}

export function getPluginSettingsStateKey(pluginId: string) {
  return `plugins.settings.${pluginId}`;
}

export function getPluginSchemaAppliedStateKey(pluginId: string) {
  return `plugins.schema.applied.${pluginId}`;
}

export function getPluginRuntimeReloadRequiredStateKey(pluginId: string) {
  return `plugins.runtime.reloadRequired.${pluginId}`;
}
