import fs from "node:fs/promises";
import path from "node:path";

const WINDOWS_RESERVED_NAMES = new Set([
  "CON",
  "PRN",
  "AUX",
  "NUL",
  "COM1",
  "COM2",
  "COM3",
  "COM4",
  "COM5",
  "COM6",
  "COM7",
  "COM8",
  "COM9",
  "LPT1",
  "LPT2",
  "LPT3",
  "LPT4",
  "LPT5",
  "LPT6",
  "LPT7",
  "LPT8",
  "LPT9",
]);

export function assertValidItemName(rawValue: unknown) {
  const value = String(rawValue ?? "").trim();

  if (!value) {
    throw new Error("El nombre no puede estar vacío.");
  }

  if (value === "." || value === "..") {
    throw new Error("El nombre ingresado no es válido.");
  }

  if (/[<>:"/\\|?*\u0000-\u001F]/.test(value)) {
    throw new Error("El nombre contiene caracteres no permitidos.");
  }

  if (/[. ]$/.test(value)) {
    throw new Error("El nombre no puede terminar con punto o espacio.");
  }

  const baseName = path.parse(value).name.toUpperCase();

  if (WINDOWS_RESERVED_NAMES.has(baseName)) {
    throw new Error("El nombre ingresado está reservado por el sistema.");
  }

  return value;
}

export function buildFileNameFromBaseName(baseName: unknown, extension: unknown) {
  const validBaseName = assertValidItemName(baseName);
  const normalizedExtension = String(extension ?? "")
    .replace(/^\./, "")
    .trim();

  return normalizedExtension
    ? `${validBaseName}.${normalizedExtension}`
    : validBaseName;
}

export async function renameVaultItem(item: any, nextNameInput: unknown) {
  const nextName = assertValidItemName(nextNameInput);

  if (nextName === item.name) {
    return {
      renamed: false,
      oldName: item.name,
      oldPath: item.path,
      oldExtension: item.extension ?? null,
      newName: item.name,
      newPath: item.path,
    };
  }

  const oldName = item.name;
  const oldPath = item.path;
  const oldExtension =
    item.extension ??
    (path.extname(String(oldName || "")).replace(/^\./, "") || null);
  const newPath = path.join(path.dirname(oldPath), nextName);

  await fs.rename(oldPath, newPath);

  item.name = nextName;
  item.path = newPath;

  if (!item.type || item.type === "file") {
    item.extension = path.extname(nextName).replace(/^\./, "") || null;
  }

  return {
    renamed: true,
    oldName,
    oldPath,
    oldExtension,
    newName: nextName,
    newPath,
  };
}

export function restoreRenamedVaultItem(item: any, renameResult: any) {
  if (!renameResult?.renamed) {
    return;
  }

  item.name = renameResult.oldName;
  item.path = renameResult.oldPath;
  item.extension = renameResult.oldExtension ?? null;
}

export async function rollbackRenamedVaultItem(item: any, renameResult: any) {
  if (!renameResult?.renamed) {
    return;
  }

  await fs.rename(renameResult.newPath, renameResult.oldPath);
  restoreRenamedVaultItem(item, renameResult);
}
